// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {ISystem} from "../interfaces/ISystem.sol";

/// @title MockSystemLowWeight — Returns low weight values for testing weight guard reverts
/// @notice weightLeft() returns refTime = 1,000,000 (below the 5B threshold in TesseractVault)
/// @dev Used ONLY in testing to verify the weight guard blocks rebalance.
contract MockSystemLowWeight is ISystem {
    function hashBlake256(bytes memory input) external pure returns (bytes32 digest) {
        digest = keccak256(input);
    }

    function hashBlake128(bytes memory input) external pure returns (bytes32 digest) {
        digest = bytes32(bytes16(keccak256(input)));
    }

    function toAccountId(address input) external pure returns (bytes memory) {
        return abi.encodePacked(input);
    }

    function callerIsOrigin() external pure returns (bool) {
        return true;
    }

    function callerIsRoot() external pure returns (bool) {
        return false;
    }

    function minimumBalance() external pure returns (uint256) {
        return 10_000;
    }

    function ownCodeHash() external pure returns (bytes32) {
        return bytes32(0);
    }

    /// @notice Returns LOW weight — below the 5_000_000_000 threshold
    function weightLeft() external pure returns (uint64 refTime, uint64 proofSize) {
        refTime = 1_000_000; // Far below 5B threshold
        proofSize = 0;
    }

    function terminate(address) external pure {
        revert("MockSystemLowWeight: not supported");
    }

    function sr25519Verify(uint8[64] calldata, bytes calldata, bytes32) external pure returns (bool) {
        return true;
    }

    function ecdsaToEthAddress(uint8[33] calldata) external pure returns (bytes20) {
        return bytes20(0);
    }
}

