///         When swap() calls transfer() to send output tokens, this contract
///         attempts to call swap() again, which must revert.
contract ReentrancyAttacker {
    string public name = "Attack Token";
    string public symbol = "ATK";
    uint8 public constant decimals = 10;

    uint256 public totalSupply;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    address public swapContract;
    uint32 public attackAssetIdIn;
    uint32 public attackAssetIdOut;
    bool public attacking;

    function setAttackParams(address _swap, uint32 _idIn, uint32 _idOut) external {
        swapContract = _swap;
        attackAssetIdIn = _idIn;
        attackAssetIdOut = _idOut;
    }

    function mint(address to, uint256 amount) external {
        totalSupply += amount;
        balanceOf[to] += amount;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowance[msg.sender][spender] = amount;
        return true;
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        balanceOf[msg.sender] -= amount;
        balanceOf[to] += amount;

        // Reentrancy attack: when swap sends output tokens, try to re-enter
        if (attacking && msg.sender == swapContract) {
            attacking = false; // prevent infinite recursion
            // This MUST revert with ReentrancyGuardReentrantCall()
            ISwapReentrant(swapContract).swap(attackAssetIdIn, attackAssetIdOut, 1, 0);
        }

        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        allowance[from][msg.sender] -= amount;
        balanceOf[from] -= amount;
        balanceOf[to] += amount;
        return true;
    }

    /// @notice Approve an external token contract so swap can pull input tokens
    function approveExternal(address token, address spender, uint256 amount) external {
        IERC20Approve(token).approve(spender, amount);
    }

    /// @notice Initiate the attack: calls swap() which will trigger transfer() callback
    function startAttack(uint256 amount) external {
        attacking = true;
        ISwapReentrant(swapContract).swap(attackAssetIdIn, attackAssetIdOut, amount, 0);
    }
}

